  // select feeding an OR-accumulation pattern, which the legacy model handles
  // differently. This avoids mismatches like in PR115744-derived cases.
  {
    bool HasSelectOrPattern = false;
    for (BasicBlock *BB : OrigLoop->blocks()) {
      for (Instruction &I : *BB) {
        if (auto *SI = dyn_cast<SelectInst>(&I)) {
          for (User *U : SI->users()) {
            auto *BO = dyn_cast<BinaryOperator>(U);
            if (BO && BO->getOpcode() == Instruction::Or) {
